// ─── Verse picker — seeded per day+hour+minute, cycles through full pool ──────
function getDayOfYear(d) {
  return Math.floor((d - new Date(d.getFullYear(), 0, 0)) / 86400000);
}

function getVerse(date) {
  const day  = getDayOfYear(date);
  const hour = date.getHours();
  const min  = date.getMinutes();
  // Unique index for this exact minute, spreads evenly across the pool
  const idx = (day * 1440 + hour * 60 + min) % VERSES.length;
  return VERSES[idx];
}

function formatTime(date) {
  return {
    h: String(date.getHours() % 12 || 12).padStart(2, "0"),
    m: String(date.getMinutes()).padStart(2, "0"),
  };
}

// ─── Seeded random & palettes ─────────────────────────────────────────────────
function seededRand(seed) {
  let s = seed;
  return () => { s=(s*1664525+1013904223)&0xffffffff; return (s>>>0)/0xffffffff; };
}

